class Cart:
    def __init__(self):
        self.items = []

    def print_cart_contents(self):
        if not self.items:
            print("The cart is empty")
        else:
            for item in self.items:
                print(item)

# The default_test function is used for testing; do not modify it.
def default_test():
    cart = Cart()
    cart.print_cart_contents()
